query:
UPDATE follow_ups f
INNER JOIN (
  SELECT id, ROW_NUMBER() OVER (PARTITION BY surveyId ORDER BY createdAt ASC) as rn
  FROM follow_ups
) ranked ON f.id = ranked.id
SET f.round = ranked.rn;

